import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import AdminLayout from '../components/admin/AdminLayout';
import authService from '../services/authService';
import api from '../services/api';

export default function AdminDashboard() {
  const navigate = useNavigate();
  const [cmsStatus, setCmsStatus] = useState('loading');
  const [userPages, setUserPages] = useState([]);
  const [selectedPage, setSelectedPage] = useState(null);
  const [pageSections, setPageSections] = useState([]);
  const [showNewPageModal, setShowNewPageModal] = useState(false);
  const [showSectionModal, setShowSectionModal] = useState(false);
  const [showCardModal, setShowCardModal] = useState(false);
  const [newPageForm, setNewPageForm] = useState({ slug: '', title: '', isPublished: false });
  const [sectionForm, setSectionForm] = useState({ type: 'default', title: '', content: '', position: 0 });
  const [cardForm, setCardForm] = useState({ title: '', description: '', icon: '' });
  const [editingCardSectionId, setEditingCardSectionId] = useState(null);

  const [contentData, setContentData] = useState({
    hero: null, benefits: null, features: null, pricing: null, steps: null, faq: null, cta: null
  });
  const [showEditModal, setShowEditModal] = useState(false);
  const [editingStaticSection, setEditingStaticSection] = useState(null);
  const [formData, setFormData] = useState({});

  useEffect(() => {
    if (!authService.isAdmin()) {
      navigate('/login');
      return;
    }
    checkCmsStatus();
  }, []);

  const checkCmsStatus = async () => {
    try {
      await api.get('/admin/test');
      setCmsStatus('available');
      loadUserPages();
    } catch (e) {
      setCmsStatus('unavailable');
    }
    loadContentData();
  };

  const loadUserPages = async () => {
    try {
      const response = await api.get('/admin/pages');
      setUserPages(response.data || []);
    } catch (e) { setUserPages([]); }
  };

  const loadPageSections = async (pageId) => {
    try {
      const response = await api.get(`/admin/pages/${pageId}`);
      setPageSections(response.data.sections || []);
    } catch (e) { setPageSections([]); }
  };

  const handleSelectPage = (page) => { setSelectedPage(page); loadPageSections(page.id); };

  const handleCreatePage = async (e) => {
    e.preventDefault();
    try {
      await api.post('/admin/pages', newPageForm);
      setShowNewPageModal(false);
      setNewPageForm({ slug: '', title: '', isPublished: false });
      loadUserPages();
    } catch (err) { alert('Erreur lors de la création'); }
  };

  const handleDeletePage = async (pageId) => {
    if (!window.confirm('Supprimer cette page ?')) return;
    try { await api.delete(`/admin/pages/${pageId}`); setSelectedPage(null); setPageSections([]); loadUserPages(); }
    catch (err) { alert('Erreur'); }
  };

  const handleCreateSection = (e) => {
    e.preventDefault();
    api.post(`/admin/pages/${selectedPage.id}/sections`, sectionForm)
      .then(() => { setShowSectionModal(false); setSectionForm({ type: 'default', title: '', content: '', position: 0 }); loadPageSections(selectedPage.id); })
      .catch(err => alert('Erreur'));
  };

  const handleDeleteSection = async (sectionId) => {
    if (!window.confirm('Supprimer cette section ?')) return;
    try { await api.delete(`/admin/sections/${sectionId}`); loadPageSections(selectedPage.id); }
    catch (err) { alert('Erreur'); }
  };

  const handleCreateCard = (e) => {
    e.preventDefault();
    api.post(`/admin/sections/${editingCardSectionId}/cards`, cardForm)
      .then(() => { setShowCardModal(false); setCardForm({ title: '', description: '', icon: '' }); setEditingCardSectionId(null); loadPageSections(selectedPage.id); })
      .catch(err => alert('Erreur'));
  };

  const handleDeleteCard = async (cardId) => {
    if (!window.confirm('Supprimer cette carte ?')) return;
    try { await api.delete(`/admin/cards/${cardId}`); loadPageSections(selectedPage.id); }
    catch (err) { alert('Erreur'); }
  };

  const loadContentData = () => {
    setContentData({
      hero: { title: "Devis Gratuit", subtitle: "Assurance Décennale Électricien", buttonText: "Obtenir mon devis" },
      benefits: { title: "Pourquoi nous choisir ?", items: [{ title: "Devis gratuit" }, { title: "Comparatif impartial" }, { title: "Réponse sous 24h" }] },
      features: { title: "Nos garanties", items: [{ title: "RC Pro" }, { title: "Garantie Décennale" }, { title: "Assistance juridique" }] },
      pricing: { title: "Tarifs transparents", plans: [{ name: "Solo" }, { name: "Artisan" }, { name: "Entreprise" }] },
      steps: { title: "Comment ça marche ?", steps: [{ title: "1. Comparez" }, { title: "2. Recevez" }, { title: "3. Économisez" }] },
      faq: { title: "Questions fréquentes", questions: [{ question: "Obligatoire ?" }, { question: "Durée ?" }, { question: "Délai ?" }] },
      cta: { title: "Prêt à economiser ?", buttonText: "Obtenir mon devis gratuit" }
    });
  };

  const handleEditStaticSection = (sectionName, data) => {
    setEditingStaticSection(sectionName);
    setFormData(data);
    setShowEditModal(true);
  };

  const handleSaveStaticSection = (e) => {
    e.preventDefault();
    setContentData({ ...contentData, [editingStaticSection]: formData });
    setShowEditModal(false);
    alert('Contenu mis à jour !');
  };

  const getSectionIcon = (type) => {
    const icons = { hero: 'fa-bolt', features: 'fa-star', benefits: 'fa-handshake', pricing: 'fa-tag', steps: 'fa-list-ol', faq: 'fa-question-circle', cta: 'fa-bullhorn', default: 'fa-th-large' };
    return icons[type] || 'fa-th-large';
  };

  const getSectionTitle = (name) => {
    const titles = { hero: 'Hero', benefits: 'Avantages', features: 'Caractéristiques', pricing: 'Tarifs', steps: 'Étapes', faq: 'FAQ', cta: 'CTA' };
    return titles[name] || name;
  };

  return (
    <AdminLayout>
      <div>
        <div className="mb-6 flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold text-gray-900">Gestion du Site Web</h1>
            <p className="text-gray-600 mt-1 text-lg">Créez des pages, sections et cartes</p>
          </div>
          <button onClick={() => setShowNewPageModal(true)} className="bg-yellow-500 text-white px-5 py-2.5 rounded-lg hover:bg-yellow-600 font-medium flex items-center gap-2 shadow-md">
            <i className="fas fa-plus"></i> Nouvelle Page
          </button>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Left: Pages */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-100">
            <div className="p-5 border-b border-gray-100 bg-purple-50">
              <h2 className="text-xl font-bold text-gray-900 flex items-center gap-2"><i className="fas fa-file-alt text-purple-600"></i> Pages</h2>
            </div>
            <div className="divide-y divide-gray-100 max-h-[500px] overflow-y-auto">
              {userPages.length === 0 ? (
                <div className="p-8 text-center text-gray-500"><i className="fas fa-folder-open text-4xl text-gray-300 mb-3"></i><p>Aucune page</p></div>
              ) : (
                userPages.map((page) => (
                  <div key={page.id} className={`p-4 flex items-center justify-between hover:bg-gray-50 cursor-pointer ${selectedPage?.id === page.id ? 'bg-yellow-50 border-l-4 border-yellow-500' : ''}`} onClick={() => handleSelectPage(page)}>
                    <div><h3 className="font-medium text-gray-900">{page.title}</h3><p className="text-sm text-gray-500">/{page.slug}</p></div>
                    <div className="flex items-center gap-2">
                      <span className={`px-2 py-1 text-xs rounded-full ${page.isPublished ? 'bg-green-100 text-green-600' : 'bg-gray-100 text-gray-600'}`}>{page.isPublished ? 'Publié' : 'Brouillon'}</span>
                      <button onClick={(e) => { e.stopPropagation(); handleDeletePage(page.id); }} className="text-red-600 hover:text-red-800 p-2"><i className="fas fa-trash"></i></button>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>

          {/* Right: Sections */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-100">
            <div className="p-5 border-b border-gray-100 bg-yellow-50 flex items-center justify-between">
              <div>
                <h2 className="text-xl font-bold text-gray-900 flex items-center gap-2"><i className="fas fa-layer-group text-yellow-600"></i> Sections & Cartes</h2>
                {selectedPage && <p className="text-sm text-gray-500 mt-1">Page: {selectedPage.title}</p>}
              </div>
              {selectedPage && <button onClick={() => setShowSectionModal(true)} className="bg-yellow-500 text-white px-3 py-2 rounded-lg hover:bg-yellow-600 text-sm"><i className="fas fa-plus mr-1"></i> Section</button>}
            </div>
            <div className="divide-y divide-gray-100 max-h-[500px] overflow-y-auto">
              {!selectedPage ? (
                <div className="p-8 text-center text-gray-500"><i className="fas fa-hand-pointer text-4xl text-gray-300 mb-3"></i><p>Sélectionnez une page</p></div>
              ) : pageSections.length === 0 ? (
                <div className="p-8 text-center text-gray-500"><i className="fas fa-th-large text-4xl text-gray-300 mb-3"></i><p>Aucune section</p></div>
              ) : (
                pageSections.map((section) => (
                  <div key={section.id} className="p-4">
                    <div className="flex items-center justify-between mb-2">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 bg-yellow-100 rounded-lg flex items-center justify-center"><i className={`fas ${getSectionIcon(section.type)} text-yellow-600`}></i></div>
                        <div><h4 className="font-medium text-gray-900">{section.title || 'Section'}</h4><p className="text-xs text-gray-500">{section.type}</p></div>
                      </div>
                      <button onClick={() => handleDeleteSection(section.id)} className="text-red-600 hover:text-red-800"><i className="fas fa-trash"></i></button>
                    </div>
                    <div className="ml-13 pl-13">
                      <div className="flex items-center justify-between mb-2"><span className="text-sm font-medium text-gray-700">Cartes</span><button onClick={() => { setEditingCardSectionId(section.id); setShowCardModal(true); }} className="text-xs text-yellow-600">+ Ajouter</button></div>
                      {section.cards?.length > 0 ? (
                        <div className="space-y-1">{section.cards.map((card) => (<div key={card.id} className="bg-gray-50 rounded p-2 flex items-center justify-between"><div className="flex items-center gap-2">{card.icon && <i className={`fas ${card.icon} text-yellow-500`}></i>}<span className="text-sm">{card.title}</span></div><button onClick={() => handleDeleteCard(card.id)} className="text-red-500 text-xs">×</button></div>))}</div>
                      ) : (<p className="text-xs text-gray-400">Aucune carte</p>)}
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>

        {/* Static Content */}
        <div className="mt-6 bg-white rounded-xl shadow-sm border border-gray-100">
          <div className="p-5 border-b border-gray-100 bg-blue-50">
            <h2 className="text-xl font-bold text-gray-900 flex items-center gap-2"><i className="fas fa-cog text-blue-600"></i> Contenu du Site</h2>
          </div>
          <div className="divide-y divide-gray-100">
            {Object.keys(contentData).map((sectionName) => (
              <div key={sectionName} className="p-4 flex items-center justify-between hover:bg-gray-50">
                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-yellow-100 rounded-lg flex items-center justify-center"><i className={`fas ${getSectionIcon(sectionName)} text-yellow-600 text-lg`}></i></div>
                  <div><h3 className="font-medium text-gray-900">{getSectionTitle(sectionName)}</h3><p className="text-sm text-gray-500">{contentData[sectionName]?.title}</p></div>
                </div>
                <button onClick={() => handleEditStaticSection(sectionName, contentData[sectionName])} className="bg-yellow-500 text-white px-4 py-2 rounded-lg hover:bg-yellow-600 text-sm">Modifier</button>
              </div>
            ))}
          </div>
        </div>

        {/* New Page Modal */}
        {showNewPageModal && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-xl w-full max-w-md">
              <div className="p-5 border-b border-gray-100 flex justify-between items-center"><h2 className="text-xl font-bold">Nouvelle Page</h2><button onClick={() => setShowNewPageModal(false)} className="text-2xl text-gray-400">×</button></div>
              <form onSubmit={handleCreatePage} className="p-5 space-y-4">
                <div><label className="block text-sm font-medium mb-1">Titre</label><input type="text" value={newPageForm.title} onChange={(e) => setNewPageForm({ ...newPageForm, title: e.target.value, slug: e.target.value.toLowerCase().replace(/\s+/g, '-') })} className="w-full px-4 py-2 border rounded-lg" required /></div>
                <div><label className="block text-sm font-medium mb-1">URL</label><input type="text" value={newPageForm.slug} onChange={(e) => setNewPageForm({ ...newPageForm, slug: e.target.value.toLowerCase().replace(/\s+/g, '-') })} className="w-full px-4 py-2 border rounded-lg" required /></div>
                <div className="flex items-center gap-2"><input type="checkbox" checked={newPageForm.isPublished} onChange={(e) => setNewPageForm({ ...newPageForm, isPublished: e.target.checked })} /><span className="text-sm">Publier</span></div>
                <div className="flex gap-2 pt-4"><button type="button" onClick={() => setShowNewPageModal(false)} className="flex-1 py-2 border rounded-lg">Annuler</button><button type="submit" className="flex-1 py-2 bg-yellow-500 text-white rounded-lg">Créer</button></div>
              </form>
            </div>
          </div>
        )}

        {/* New Section Modal */}
        {showSectionModal && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-xl w-full max-w-md">
              <div className="p-5 border-b border-gray-100 flex justify-between items-center"><h2 className="text-xl font-bold">Nouvelle Section</h2><button onClick={() => setShowSectionModal(false)} className="text-2xl text-gray-400">×</button></div>
              <form onSubmit={handleCreateSection} className="p-5 space-y-4">
                <div><label className="block text-sm font-medium mb-1">Type</label><select value={sectionForm.type} onChange={(e) => setSectionForm({ ...sectionForm, type: e.target.value })} className="w-full px-4 py-2 border rounded-lg"><option value="default">Default</option><option value="hero">Hero</option><option value="features">Features</option><option value="benefits">Benefits</option><option value="pricing">Pricing</option><option value="steps">Steps</option><option value="faq">FAQ</option><option value="cta">CTA</option></select></div>
                <div><label className="block text-sm font-medium mb-1">Titre</label><input type="text" value={sectionForm.title} onChange={(e) => setSectionForm({ ...sectionForm, title: e.target.value })} className="w-full px-4 py-2 border rounded-lg" /></div>
                <div><label className="block text-sm font-medium mb-1">Contenu</label><textarea value={sectionForm.content} onChange={(e) => setSectionForm({ ...sectionForm, content: e.target.value })} className="w-full px-4 py-2 border rounded-lg" rows={3} /></div>
                <div className="flex gap-2 pt-4"><button type="button" onClick={() => setShowSectionModal(false)} className="flex-1 py-2 border rounded-lg">Annuler</button><button type="submit" className="flex-1 py-2 bg-yellow-500 text-white rounded-lg">Créer</button></div>
              </form>
            </div>
          </div>
        )}

        {/* New Card Modal */}
        {showCardModal && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-xl w-full max-w-md">
              <div className="p-5 border-b border-gray-100 flex justify-between items-center"><h2 className="text-xl font-bold">Nouvelle Carte</h2><button onClick={() => setShowCardModal(false)} className="text-2xl text-gray-400">×</button></div>
              <form onSubmit={handleCreateCard} className="p-5 space-y-4">
                <div><label className="block text-sm font-medium mb-1">Titre</label><input type="text" value={cardForm.title} onChange={(e) => setCardForm({ ...cardForm, title: e.target.value })} className="w-full px-4 py-2 border rounded-lg" /></div>
                <div><label className="block text-sm font-medium mb-1">Description</label><textarea value={cardForm.description} onChange={(e) => setCardForm({ ...cardForm, description: e.target.value })} className="w-full px-4 py-2 border rounded-lg" rows={2} /></div>
                <div><label className="block text-sm font-medium mb-1">Icône (fa-star)</label><input type="text" value={cardForm.icon} onChange={(e) => setCardForm({ ...cardForm, icon: e.target.value })} className="w-full px-4 py-2 border rounded-lg" placeholder="fa-check" /></div>
                <div className="flex gap-2 pt-4"><button type="button" onClick={() => setShowCardModal(false)} className="flex-1 py-2 border rounded-lg">Annuler</button><button type="submit" className="flex-1 py-2 bg-yellow-500 text-white rounded-lg">Créer</button></div>
              </form>
            </div>
          </div>
        )}

        {/* Edit Static Content Modal */}
        {showEditModal && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-xl w-full max-w-lg max-h-[80vh] overflow-y-auto">
              <div className="p-5 border-b border-gray-100 flex justify-between items-center"><h2 className="text-xl font-bold">{getSectionTitle(editingStaticSection)}</h2><button onClick={() => setShowEditModal(false)} className="text-2xl text-gray-400">×</button></div>
              <form onSubmit={handleSaveStaticSection} className="p-5 space-y-4">
                <div><label className="block text-sm font-medium mb-1">Titre</label><input type="text" value={formData.title || ''} onChange={(e) => setFormData({ ...formData, title: e.target.value })} className="w-full px-4 py-2 border rounded-lg" /></div>
                <div className="flex gap-2 pt-4"><button type="button" onClick={() => setShowEditModal(false)} className="flex-1 py-2 border rounded-lg">Annuler</button><button type="submit" className="flex-1 py-2 bg-yellow-500 text-white rounded-lg">Sauvegarder</button></div>
              </form>
            </div>
          </div>
        )}
      </div>
    </AdminLayout>
  );
}
